{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표는 금요일 15:00 KST로 한다.",
        "conditions": ["스모크 테스트 통과"],
        "notes": "고객 또는 외부 파트너는 언급되지 않았다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "conditions": ["packageName mismatch 발생"],
        "notes": "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "outcome": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "내부 stretch goal로만 남음",
        "reason": "Doyun이 스모크 테스트 통과가 먼저 필요하다고 이의 제기함"
      },
      {
        "goal": "README 설치 단계를 목요일까지 가능하면 검토한다.",
        "owner": null,
        "status": "확정 작업 아님",
        "reason": "담당자가 배정되지 않음"
      }
    ],
    "non_decisions": [
      {
        "item": "최종 릴리스 승인 권한자",
        "status": "결정되지 않음"
      },
      {
        "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부",
        "status": "결정되지 않음"
      },
      {
        "item": "README 설치 단계 검토 담당자",
        "status": "배정되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다.",
        "category": "release_readiness"
      },
      {
        "risk": "README 설치 단계가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있다.",
        "category": "documentation"
      }
    ],
    "open_questions": [
      "누가 최종 릴리스 승인 권한을 가지는가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_explicit"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "confirmed_explicit"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일, 가능하면",
      "status": "not_confirmed_no_owner",
      "source_certainty": "mentioned_but_unassigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 재실행 결과를 확인한다.",
      "스모크 테스트 통과 여부에 따라 금요일 15:00 KST 공개 릴리스 목표가 유효한지 확인한다.",
      "Doyun의 action_items.md 실패 triage note 작성 여부를 금요일 12:00 KST 기준으로 확인한다.",
      "Minjun의 스모크 결과 게시 후 Hara가 생성된 tarball 경로를 확인했는지 확인한다.",
      "README 설치 단계 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확정한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owners": "담당자가 명시되지 않은 항목에는 owner를 null로 둔다.",
    "deadlines": "정확한 마감이 명시되지 않은 항목에는 due를 null 또는 원문 수준의 제한 표현으로만 기록한다.",
    "release_authority": "최종 릴리스 승인 권한자는 결정되지 않았으므로 특정 인물로 지정하지 않는다."
  }
}
